// EP-103: heuristic unit-distance packing proxy for minimal diameter.
{
  const rng = makeRng(20260304 ^ 103);

  function energy(points, minDist, lambda) {
    let e = 0;
    let maxD = 0;
    for (let i = 0; i < points.length; i += 1) {
      for (let j = i + 1; j < points.length; j += 1) {
        const dx = points[i][0] - points[j][0];
        const dy = points[i][1] - points[j][1];
        const d = Math.hypot(dx, dy);
        if (d < minDist) e += lambda * (minDist - d) * (minDist - d);
        if (d > maxD) maxD = d;
      }
    }
    return { e: e + maxD, maxD };
  }

  function randomPoints(n) {
    const pts = [];
    for (let i = 0; i < n; i += 1) pts.push([rng() * 3, rng() * 3]);
    return pts;
  }

  function optimize(n, iters) {
    let pts = randomPoints(n);
    let { e, maxD } = energy(pts, 1, 10);
    for (let t = 0; t < iters; t += 1) {
      const i = Math.floor(rng() * n);
      const old = pts[i].slice();
      pts[i][0] += (rng() - 0.5) * 0.2;
      pts[i][1] += (rng() - 0.5) * 0.2;
      const ne = energy(pts, 1, 10);
      if (ne.e < e || rng() < Math.exp((e - ne.e) / 0.2)) {
        e = ne.e;
        maxD = ne.maxD;
      } else {
        pts[i] = old;
      }
    }
    return { maxD, pts };
  }

  const rows = [];
  for (const n of [7, 8, 9, 10]) {
    let best = Infinity;
    const sigs = new Set();
    for (let r = 0; r < 20; r += 1) {
      const { maxD, pts } = optimize(n, 800);
      if (maxD < best) best = maxD;
      // signature: rounded multiset of distances
      const dists = [];
      for (let i = 0; i < pts.length; i += 1) {
        for (let j = i + 1; j < pts.length; j += 1) {
          const dx = pts[i][0] - pts[j][0];
          const dy = pts[i][1] - pts[j][1];
          dists.push(Math.round(Math.hypot(dx, dy) * 1000));
        }
      }
      dists.sort((a, b) => a - b);
      sigs.add(dists.slice(0, 30).join(','));
    }
    rows.push({ n, best_diameter_est: Number(best.toPrecision(6)), distinct_signature_count: sigs.size });
  }

  out.results.ep103 = {
    description: 'Heuristic plane packing proxy with unit-distance penalty; counts distinct distance signatures among local minima.',
    rows,
  };
}
